import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader);
    }

    @Test
    void testReadLine_NonNullNonEmptyLine() throws IOException, NoSuchFieldException, IllegalAccessException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn("abc").when(spyReader).readLine();

        // To avoid infinite recursion, call real method for readLine() and mock super.readLine() via reflection
        // But since super.readLine() cannot be mocked directly, we mock readLine() to call a helper method

        // Instead, use doCallRealMethod() and mock the underlying Reader

        // So, reset the spy and mock underlying Reader.readLine() via spy on BufferedReader's super method

        // The simplest fix: mock the underlying Reader to provide the line

        // So, instead of mocking spyReader.readLine(), mock the underlying Reader to provide the line

        // However, BufferedReader.readLine() calls read() methods on the Reader, so mocking Reader.read() to simulate lines is complex.

        // Alternative: create a subclass of ExtendedBufferedReader with overridden readLine() that calls super.readLine()

        // Since the error is about missing superReadLine(), replace doReturn(...).when(spyReader).superReadLine()
        // with doReturn(...).when(spyReader).readLine() and call the real method inside readLine() via doCallRealMethod()

        // But this leads to recursion.

        // So best solution: use spyReader and mock the underlying Reader to simulate lines.

        // Mock the underlying Reader to return the line "abc" when readLine() is called

        // Because BufferedReader.readLine() reads from Reader, we can mock Reader.read() to simulate the line "abc\n"

        // Implement a helper class for Reader that returns the characters of "abc\n" then EOF

        // But since the test is about ExtendedBufferedReader, let's just create a real ExtendedBufferedReader with a StringReader

        // So the simplest fix: replace mockReader with a java.io.StringReader containing the test string

        // Implement the fixed tests below:

        // ----

        // So for this test, create new ExtendedBufferedReader with StringReader("abc\n")

        ExtendedBufferedReader reader = new ExtendedBufferedReader(new java.io.StringReader("abc\n"));
        String line = reader.readLine();

        assertEquals("abc", line);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = (int) lastCharField.get(reader);
        assertEquals('c', lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = (int) lineCounterField.get(reader);
        assertEquals(1, lineCounter);
    }

    @Test
    void testReadLine_NonNullEmptyLine() throws IOException, NoSuchFieldException, IllegalAccessException {
        ExtendedBufferedReader reader = new ExtendedBufferedReader(new java.io.StringReader("\n"));
        String line = reader.readLine();

        assertEquals("", line);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = (int) lastCharField.get(reader);
        // lastChar should remain unchanged (default UNDEFINED = -2)
        assertEquals(ExtendedBufferedReader.UNDEFINED, lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = (int) lineCounterField.get(reader);
        assertEquals(1, lineCounter);
    }

    @Test
    void testReadLine_NullLine() throws IOException, NoSuchFieldException, IllegalAccessException {
        ExtendedBufferedReader reader = new ExtendedBufferedReader(new java.io.StringReader(""));
        String line = reader.readLine();

        assertNull(line);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastChar = (int) lastCharField.get(reader);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);

        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        int lineCounter = (int) lineCounterField.get(reader);
        // lineCounter should not increment on null line
        assertEquals(0, lineCounter);
    }

    @Test
    void testReadLine_IOException() throws IOException {
        Reader throwingReader = mock(Reader.class);
        ExtendedBufferedReader reader = new ExtendedBufferedReader(throwingReader);
        // Mock the underlying Reader to throw IOException on read()
        doThrow(new IOException("Test IO Exception")).when(throwingReader).read(any(char[].class), anyInt(), anyInt());

        IOException thrown = assertThrows(IOException.class, reader::readLine);
        assertEquals("Test IO Exception", thrown.getMessage());
    }
}
